#include <bits/stdc++.h> 
using namespace std;
const int N=1000005;
int n,q,a[N],ls[N],rs[N],f[N],flag[N],cnt=0,cnt2,op[N];
string s;
stack<int> st;
void dfs(int u)
{
	if(u<=n) return ;
	dfs(ls[u]);
	dfs(rs[u]);
	if(op[u]==1) a[u]=a[ls[u]]&a[rs[u]];
	else a[u]=a[ls[u]]|a[rs[u]];
	if(flag[u]==1) a[u]=!a[u];
}
void fun(int u)
{
	if(u==0) return ;
	if(u<=n)
	{
		fun(f[u]);
		return ;
	}
	int t=a[u];
	if(op[u]==1) a[u]=a[ls[u]]&a[rs[u]];
	else a[u]=a[ls[u]]|a[rs[u]];
	if(flag[u]==1) a[u]=!a[u];
	if(t==a[u]) return ;
	fun(f[u]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	getline(cin,s);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	cnt2=n;
//	cout<<"aaa"<<endl;
	int num=0;
	for(int i=0;i<s.size();i++)
	{
//		cout<<i<<" : ";
		char c=s[i];
		if(c==' ')
		{
//			cout<<"  ' '"<<endl;
			if(num>0) st.push(num);
			num=0;
		}
		if(c=='x')
		{
//			cout<<"  'x'"<<endl;
//			st.push(++cnt);
//			cout<<"push : "<<cnt<<endl;
			continue;
		}
		if(c>='0'&&c<='9')
		{
//			cout<<"  '0-9'"<<endl;
			num=num*10+(c-'0');
		}
		if(c=='!')
		{
//			cout<<"  '!'"<<endl;
			flag[st.top()]=!flag[st.top()];
			if(st.top()<=n) a[st.top()]=!a[st.top()];
		}
		else if(c=='&'||c=='|')
		{
//			cout<<"  '&/|'"<<endl;
			int x=st.top();
//			cout<<"pop : "<<x<<endl;
			st.pop();
			int y=st.top();
//			cout<<"pop : "<<y<<endl;
			st.pop();
			st.push(++cnt2);
//			cout<<"push : "<<cnt2<<endl;
			if(c=='&') op[cnt2]=1;
			else op[cnt2]=2;
			f[x]=f[y]=cnt2;
			ls[cnt2]=x;
			rs[cnt2]=y;
		}
	}
	for(int i=n+1;i<=cnt2;i++)
	{
//		cout<<i<<"  flag : "<<flag[i]<<"  op : "<<op[i]<<"  ls : "<<ls[i]<<"  rs : "<<rs[i]<<"\n";
	}
//	cout<<"aaa"<<endl;
	dfs(cnt2);
	cin>>q;
//	cout<<"bbb"<<endl;
	while(q--)
	{
		int x;
		cin>>x;
		a[x]=!a[x];
		fun(x);
		cout<<a[cnt2]<<"\n";
		a[x]=!a[x];
		fun(x);
//		cout<<"cc"<<endl;
	}
	return 0;
}
